   315→        .filter((value) => value.length > 0),
   316→    ),
   317→  );
   318→
   319→  const profileEntries = await Promise.all(
   320→    userIds.map(async (userId) => [userId, await getUserProfile(userId)] as const),
   321→  );
   322→  const profileByUserId = new Map(profileEntries);
   323→  const output: AdminSubmissionEvent[] = [];
   324→  let fallbackLookups = 0;
   325→
   326→  for (const event of sortedEvents) {
   327→    const normalizedUserId = normalizeActorId(event.userId);
   328→    const profile = profileByUserId.get(normalizedUserId) ?? null;
   329→    const emailFromProfile = typeof profile?.email === "string" ? profile.email.trim().toLowerCase() : "";
   330→    const email = emailFromProfile || (normalizedUserId.includes("@") ? normalizedUserId : null);
   331→    const name = getUserDisplayName(normalizedUserId, profile?.name ?? null, email);
   332→    let fraudCheck = getEventFraudCheck(event);
   333→    if (!fraudCheck && fallbackLookups < MAX_FORENSICS_FALLBACK_LOOKUPS) {
   334→      fallbackLookups += 1;
   335→      try {
   336→        fraudCheck = await buildFallbackFraudCheck(event);
   337→      } catch {
   338→        fraudCheck = null;
   339→      }
   340→    }
   341→
   342→    output.push({
   343→      event,
   344→      user: {
   345→        id: normalizedUserId || event.userId,
   346→        name,
   347→        email,
   348→      },
   349→      fraudCheck,
   350→    });
   351→  }
   352→
   353→  return output;
   354→}
   355→
   356→async function buildCombinedEvents(): Promise<PointEvent[]> {
   357→  const pointEvents = (await getPointEvents()).map(stripInlinePhotoData);
   358→  const legacySubmissions = await getLegacySubmissions();
   359→  const merged = mergePointEventsWithLegacy(pointEvents, legacySubmissions);
   360→  const seenExternalIds = new Set(
   361→    merged
   362→      .map((event) => (typeof event.externalId === "string" ? event.externalId.trim() : ""))
   363→      .filter((value) => value.length > 0),
   364→  );
   365→  const seenPointIds = new Set(merged.map((event) => event.pointId));
   366→  for (const seedEvent of BONAMOUSSADI_CURATED_SEED_EVENTS) {
   367→    const externalId = typeof seedEvent.externalId === "string" ? seedEvent.externalId.trim() : "";
   368→    if (externalId && seenExternalIds.has(externalId)) continue;
   369→    if (seenPointIds.has(seedEvent.pointId)) continue;
   370→    merged.push(seedEvent);
   371→    if (externalId) seenExternalIds.add(externalId);
   372→    seenPointIds.add(seedEvent.pointId);
   373→  }
   374→  return merged;
   375→}
