import React, { Suspense, useEffect, useMemo, useState } from 'react';
import { Category, DataPoint } from '../../types';
import type { MapScope, ProjectedPoint } from '../../shared/types';
import {
  BONAMOUSSADI_CENTER,
  CAMEROON_CENTER,
  bonamoussadiLeafletBounds,
  cameroonLeafletBounds,
  isWithinBonamoussadi
} from '../../shared/geofence';
import {
  Fuel,
  Landmark,
  List,
  Map as MapIcon,
  MapPin,
  Pill,
  Plus,
  ShieldCheck,
  User
} from 'lucide-react';
import { apiJson } from '../../lib/client/api';
import { detectLowEndDevice } from '../../lib/client/deviceProfile';
import BrandLogo from '../BrandLogo';

interface Props {
  onSelectPoint: (point: DataPoint) => void;
  isAuthenticated: boolean;
  isAdmin?: boolean;
  onAuth: () => void;
  onContribute: () => void;
  onProfile: () => void;
  language: 'en' | 'fr';
}

type MapPointGroup = {
  key: string;
  latitude: number;
  longitude: number;
  points: DataPoint[];
};

const HomeMap = React.lazy(() => import('./HomeMap'));

const BONAMOUSSADI_MAP_BOUNDS = bonamoussadiLeafletBounds();
const CAMEROON_MAP_BOUNDS = cameroonLeafletBounds();

const normalizeMapScope = (scope: unknown, isAdminMode: boolean): MapScope => {
  if (isAdminMode) return 'global';
  if (scope === 'cameroon' || scope === 'global') return scope;
  return 'bonamoussadi';
};

const buildMockPoints = (language: 'en' | 'fr'): DataPoint[] => {
  const t = (en: string, fr: string) => (language === 'fr' ? fr : en);
  return [
    {
      id: 'mock-pharmacy-1',
      name: 'Pharmacie de Bonamoussadi',
      type: Category.PHARMACY,
      location: 'GPS: 4.0868°, 9.7357°',
      coordinates: { latitude: 4.0868, longitude: 9.7357 },
      lastUpdated: t('18 mins ago', 'il y a 18 min'),
      availability: 'High',
      trustScore: 96,
      openingHours: '08:00 - 22:00',
      isOpenNow: true,
      isOnDuty: true,
      verified: true,
      gaps: ['openingHours']
    },
    {
      id: 'mock-fuel-1',
      name: 'TOTAL Bonamoussadi 1',
      type: Category.FUEL,
      location: 'GPS: 4.0864°, 9.7346°',
      coordinates: { latitude: 4.0864, longitude: 9.7346 },
      fuelType: 'Super',
      quality: 'Standard',
      currency: 'XAF',

