   103→    }
   104→  ];
   105→};
   106→
   107→const Home: React.FC<Props> = ({ onSelectPoint, isAuthenticated, isAdmin, onAuth, onContribute, onProfile, language }) => {
   108→  const [deviceRuntime] = useState(() => ({ lowEnd: detectLowEndDevice() }));
   109→  const [viewMode, setViewMode] = useState<'map' | 'list'>(() => (deviceRuntime.lowEnd ? 'list' : 'map'));
   110→  const [activeCategory, setActiveCategory] = useState<Category>(Category.PHARMACY);
   111→  const [points, setPoints] = useState<DataPoint[]>(() => buildMockPoints(language));
   112→  const [isLoadingPoints, setIsLoadingPoints] = useState(true);
   113→  const [mapScope, setMapScope] = useState<MapScope>(() => (isAdmin ? 'global' : 'bonamoussadi'));
