   115→  const t = (en: string, fr: string) => (language === 'fr' ? fr : en);
   116→
   117→  const selectedCityLabel =
   118→    mapScope === 'cameroon'
   119→      ? t('Cameroon', 'Cameroun')
   120→      : mapScope === 'global'
   121→        ? t('Worldwide', 'Monde entier')
   122→        : t('Bonamoussadi, Douala, Cameroon', 'Bonamoussadi, Douala, Cameroun');
   123→
   124→  const mapCenter: [number, number] =
   125→    mapScope === 'cameroon'
   126→      ? [CAMEROON_CENTER.latitude, CAMEROON_CENTER.longitude]
   127→      : mapScope === 'global'
   128→        ? [20, 0]
   129→        : [BONAMOUSSADI_CENTER.latitude, BONAMOUSSADI_CENTER.longitude];
   130→  const mapZoom = mapScope === 'cameroon' ? 6 : mapScope === 'global' ? 2 : 15;
   131→  const mapMinZoom = mapScope === 'cameroon' ? 5 : mapScope === 'global' ? 2 : 14;
   132→  const mapBounds =
   133→    mapScope === 'bonamoussadi' ? BONAMOUSSADI_MAP_BOUNDS : mapScope === 'cameroon' ? CAMEROON_MAP_BOUNDS : undefined;
   134→  const mapLockLabel =
   135→    mapScope === 'bonamoussadi'
   136→      ? t('GPS Locked', 'GPS verrouille')
   137→      : t('GPS Unlocked (Admin)', 'GPS debloque (admin)');
   138→
   139→  const formatTimeAgo = (iso: string) => {
   140→    const created = new Date(iso).getTime();
   141→    if (Number.isNaN(created)) return t('Unknown', 'Inconnu');
   142→    const diffMs = Date.now() - created;
   143→    const minutes = Math.max(1, Math.round(diffMs / 60000));
   144→    if (minutes < 60) return language === 'fr' ? `il y a ${minutes} min` : `${minutes} mins ago`;
   145→    const hours = Math.round(minutes / 60);
   146→    if (hours < 24) return language === 'fr' ? `il y a ${hours}h` : `${hours}h ago`;
   147→    const days = Math.round(hours / 24);
   148→    return language === 'fr' ? `il y a ${days}j` : `${days}d ago`;
   149→  };
   150→
   151→  const inferAvailability = (category: ProjectedPoint['category'], details: Record<string, unknown>): 'High' | 'Low' | 'Out' => {
   152→    if (category === 'pharmacy') {
   153→      if (typeof details.isOpenNow === 'boolean') return details.isOpenNow ? 'High' : 'Out';
   154→      return 'Low';
   155→    }
   156→    if (category === 'fuel_station') {
   157→      if (typeof details.hasFuelAvailable === 'boolean') return details.hasFuelAvailable ? 'High' : 'Out';
   158→      return 'Low';
   159→    }
   160→    const hasMin50000XafAvailable =
   161→      typeof details.hasMin50000XafAvailable === 'boolean'
   162→        ? details.hasMin50000XafAvailable
   163→        : typeof details.hasCashAvailable === 'boolean'
   164→          ? details.hasCashAvailable
   165→          : undefined;
   166→    if (typeof hasMin50000XafAvailable === 'boolean') return hasMin50000XafAvailable ? 'High' : 'Out';
   167→    return 'Low';
   168→  };
   169→
   170→  const mapProjectedToPoint = (point: ProjectedPoint): DataPoint => {
   171→    const details = (point.details ?? {}) as Record<string, unknown>;
   172→    const type =
   173→      point.category === 'pharmacy'
   174→        ? Category.PHARMACY
   175→        : point.category === 'fuel_station'
   176→          ? Category.FUEL
   177→          : Category.MOBILE_MONEY;
   178→    const name =
   179→      (typeof details.name === 'string' && details.name) ||
   180→      (typeof details.siteName === 'string' && details.siteName) ||
   181→      (type === Category.PHARMACY
   182→        ? t('Pharmacy', 'Pharmacie')
   183→        : type === Category.FUEL
   184→          ? t('Fuel Station', 'Station-service')
   185→          : t('Mobile Money Kiosk', 'Kiosque mobile money'));
   186→    const pricesByFuel =
   187→      details.pricesByFuel && typeof details.pricesByFuel === 'object'
   188→        ? (details.pricesByFuel as Record<string, number>)
   189→        : undefined;
   190→    const derivedPrice =
   191→      typeof details.fuelPrice === 'number'
   192→        ? details.fuelPrice
   193→        : typeof details.price === 'number'
   194→          ? details.price
   195→          : pricesByFuel
   196→            ? Object.values(pricesByFuel).find((value) => Number.isFinite(value))
   197→            : undefined;
   198→    const providers = Array.isArray(details.providers)
   199→      ? (details.providers as string[]).filter((value) => typeof value === 'string' && value.trim().length > 0)
   200→      : [];
   201→    const paymentMethods = Array.isArray(details.paymentMethods)
   202→      ? (details.paymentMethods as string[])
   203→      : Array.isArray(details.paymentModes)
