   209→      provider ||
   210→      (providers.length > 0 ? providers[0] : undefined);
   211→
   212→    return {
   213→      id: point.pointId,
   214→      name,
   215→      type,
   216→      location: `GPS: ${point.location.latitude.toFixed(4)}°, ${point.location.longitude.toFixed(4)}°`,
   217→      coordinates: { latitude: point.location.latitude, longitude: point.location.longitude },
   218→      price: typeof derivedPrice === 'number' ? derivedPrice : undefined,
   219→      fuelType:
   220→        (typeof details.fuelType === 'string' && details.fuelType) ||
   221→        (Array.isArray(details.fuelTypes) ? String(details.fuelTypes[0] ?? '') : undefined),
   222→      fuelTypes: Array.isArray(details.fuelTypes) ? (details.fuelTypes as string[]) : undefined,
   223→      pricesByFuel: pricesByFuel,
   224→      quality: typeof details.quality === 'string' ? details.quality : undefined,
   225→      currency: 'XAF',
   226→      lastUpdated: formatTimeAgo(point.updatedAt),
   227→      availability: inferAvailability(point.category, details),
